import { toTags } from '../tag.js';
import { getItem } from './item.js';
import { toUserItem } from './user.js';
export const toRoomItem = (sonolus, localize, item) => ({
    name: item.name,
    title: localize(item.title),
    subtitle: localize(item.subtitle),
    master: localize(item.master),
    masterUser: item.masterUser
        ? toUserItem(sonolus, localize, getItem(sonolus.user.items, item.masterUser, `Engine/${item.name}`, '.masterUser'))
        : undefined,
    tags: toTags(localize, item.tags),
    cover: item.cover,
    bgm: item.bgm,
    preview: item.preview,
});
